composable(
    route = "opportunity/{id}",
    arguments = listOf(navArgument("id") { type = NavType.StringType }),
    deepLinks = listOf(navDeepLink {
        uriPattern = "https://www.dev.upzi.vn/opportunity/{id}"
    })
) { entry ->
    OpportunityRoute(requireNotNull(entry.arguments?.getString("id")))
}

fun DeepLinkCoordinator.consumeIfReady(
    sessionReady: Boolean, navReady: Boolean,
    navigate: (NavCommand) -> Unit
) {
    val item = pending.value ?: return
    if (!sessionReady || !navReady || item.key in consumedKeys) return
    consumedKeys += item.key
    pending.value = null
    navigate(item.command)
}

sealed interface NavCommand {
    data class Opportunity(val id: String) : NavCommand
    data class Chat(val id: String) : NavCommand
}

fun parseDeepLink(uri: Uri): NavCommand? {
    if (uri.scheme != "https" || uri.host != "www.dev.upzi.vn") return null
    val parts = uri.pathSegments
    val id = parts.getOrNull(1)?.takeIf { it.length in 1..128 } ?: return null
    return when (parts.firstOrNull()) {
        "opportunity" -> NavCommand.Opportunity(id)
        "chat" -> NavCommand.Chat(id)
        else -> null
    }
}

override fun onNewIntent(intent: Intent) {
    super.onNewIntent(intent)
    setIntent(intent)
    deepLinkCoordinator.submit(intent.data)
}
